import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { toast } from 'react-toastify';
import api from '../services/api';

const ForgotPasswordPage = () => {
  const navigate = useNavigate();
  const [step, setStep] = useState(1); // 1: Email, 2: OTP, 3: New Password
  const [loading, setLoading] = useState(false);
  const [email, setEmail] = useState('');
  const [otp, setOtp] = useState('');
  const [newPassword, setNewPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');

  const handleEmailSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);

    try {
      const response = await api.post('/auth/forgot-password', { email });
      toast.success(response.data.message || 'OTP has been sent to your email!');
      setStep(2);
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to send OTP. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const handleOtpSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);

    try {
      const response = await api.post('/auth/verify-otp', { email, otp });
      toast.success(response.data.message || 'OTP verified successfully!');
      setStep(3);
    } catch (error) {
      toast.error(error.response?.data?.message || 'Invalid OTP. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const handleResetPassword = async (e) => {
    e.preventDefault();
    
    if (newPassword !== confirmPassword) {
      toast.error('Passwords do not match!');
      return;
    }

    if (newPassword.length < 6) {
      toast.error('Password must be at least 6 characters long!');
      return;
    }

    setLoading(true);

    try {
      const response = await api.post('/auth/reset-password', {
        email,
        otp,
        newPassword
      });
      toast.success(response.data.message || 'Password reset successfully!');
      setTimeout(() => {
        navigate('/login');
      }, 2000);
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to reset password. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const renderStep1 = () => (
    <form onSubmit={handleEmailSubmit} style={styles.form}>
      <div style={styles.inputGroup}>
        <label style={styles.label}>Email Address</label>
        <input
          type="email"
          value={email}
          onChange={(e) => setEmail(e.target.value)}
          style={styles.input}
          required
          placeholder="Enter your registered email"
        />
      </div>
      <button type="submit" style={styles.button} disabled={loading}>
        {loading ? 'Sending OTP...' : 'Send OTP'}
      </button>
    </form>
  );

  const renderStep2 = () => (
    <form onSubmit={handleOtpSubmit} style={styles.form}>
      <div style={styles.infoBox}>
        <p style={styles.infoText}>
          An OTP has been sent to <strong>{email}</strong>
        </p>
      </div>
      <div style={styles.inputGroup}>
        <label style={styles.label}>Enter OTP</label>
        <input
          type="text"
          value={otp}
          onChange={(e) => setOtp(e.target.value)}
          style={styles.otpInput}
          required
          placeholder="Enter 6-digit OTP"
          maxLength={6}
        />
      </div>
      <button type="submit" style={styles.button} disabled={loading}>
        {loading ? 'Verifying...' : 'Verify OTP'}
      </button>
      <button
        type="button"
        onClick={() => setStep(1)}
        style={styles.secondaryButton}
      >
        Change Email
      </button>
    </form>
  );

  const renderStep3 = () => (
    <form onSubmit={handleResetPassword} style={styles.form}>
      <div style={styles.inputGroup}>
        <label style={styles.label}>New Password</label>
        <input
          type="password"
          value={newPassword}
          onChange={(e) => setNewPassword(e.target.value)}
          style={styles.input}
          required
          placeholder="Enter new password"
          minLength={6}
        />
      </div>
      <div style={styles.inputGroup}>
        <label style={styles.label}>Confirm Password</label>
        <input
          type="password"
          value={confirmPassword}
          onChange={(e) => setConfirmPassword(e.target.value)}
          style={styles.input}
          required
          placeholder="Confirm new password"
          minLength={6}
        />
      </div>
      <button type="submit" style={styles.button} disabled={loading}>
        {loading ? 'Resetting...' : 'Reset Password'}
      </button>
    </form>
  );

  const getStepTitle = () => {
    switch (step) {
      case 1:
        return 'Forgot Password';
      case 2:
        return 'Verify OTP';
      case 3:
        return 'Reset Password';
      default:
        return 'Forgot Password';
    }
  };

  const getStepDescription = () => {
    switch (step) {
      case 1:
        return 'Enter your registered email address to receive an OTP';
      case 2:
        return 'Enter the 6-digit OTP sent to your email';
      case 3:
        return 'Create a new password for your account';
      default:
        return '';
    }
  };

  return (
    <div style={styles.container}>
      <div style={styles.loginBox}>
        <h2 style={styles.heading}>{getStepTitle()}</h2>
        <p style={styles.description}>{getStepDescription()}</p>

        {/* Progress Steps */}
        <div style={styles.progressContainer}>
          <div style={styles.progressStep}>
            <div style={{ ...styles.stepCircle, ...(step >= 1 ? styles.stepActive : {}) }}>1</div>
            <span style={styles.stepText}>Email</span>
          </div>
          <div style={styles.progressLine} />
          <div style={styles.progressStep}>
            <div style={{ ...styles.stepCircle, ...(step >= 2 ? styles.stepActive : {}) }}>2</div>
            <span style={styles.stepText}>OTP</span>
          </div>
          <div style={styles.progressLine} />
          <div style={styles.progressStep}>
            <div style={{ ...styles.stepCircle, ...(step >= 3 ? styles.stepActive : {}) }}>3</div>
            <span style={styles.stepText}>Reset</span>
          </div>
        </div>

        {step === 1 && renderStep1()}
        {step === 2 && renderStep2()}
        {step === 3 && renderStep3()}

        <Link to="/login" style={styles.backLink}>
          ← Back to Login
        </Link>
      </div>
    </div>
  );
};

const styles = {
  container: {
    minHeight: '100vh',
    background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    padding: '20px',
  },
  loginBox: {
    backgroundColor: 'white',
    padding: '40px',
    borderRadius: '10px',
    boxShadow: '0 10px 40px rgba(0,0,0,0.2)',
    width: '100%',
    maxWidth: '450px',
  },
  heading: {
    textAlign: 'center',
    marginBottom: '10px',
    color: '#333',
